10	  steps: Step[];
11	};
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	const ITEM_BASE: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const COMPONENT_BLOCK_SIZE = 3;
30	const COMPONENT_BLOCK_BASE = 60;
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	
33	const groupCountsByType = (items: Item[]): Map<string, number> => {
34	  const counts = new Map<string, number>();
35	  for (const item of items) {
36	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
37	  }
38	  return counts;
39	};
40	
41	const baseForGroup = (type: string, count: number): number => {
42	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
43	    return COMPONENT_BLOCK_BASE;
44	  }
45	  return count * ITEM_BASE[type];
46	};
47	
48	const calculatePolicyBase = (items: Item[]): number => {
49	  let total = 0;
50	  for (const [type, count] of groupCountsByType(items)) {
51	    total += baseForGroup(type, count);
52	  }
53	  return total;
54	};
55	
56	const roundUpInMHPCOsFavor = (amount: number): number => Math.ceil(amount);
57	
58	type ItemSurcharge = { applies: (item: Item) => boolean; rate: number };
59	
60	const ITEM_SURCHARGES: ItemSurcharge[] = [
61	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
62	  {
63	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
64	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
65	  },
66	];
67	
68	const surchargesForItem = (item: Item): number =>
69	  ITEM_SURCHARGES.reduce(
70	    (sum, { applies, rate }) => sum + (applies(item) ? ITEM_BASE[item.type] * rate : 0),
71	    0,
72	  );
73	
74	const itemSpecificSurcharges = (items: Item[]): number =>
75	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
76	
77	const quotePremium = ({ items }: Step, customer: Scenario["customer"]): number => {
78	  const policyBase = calculatePolicyBase(items);
79	  const firstContractSurcharge = policyBase * FIRST_CONTRACT_SURCHARGE_RATE;
80	  const loyaltyDiscount =
81	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
82	  const itemSurcharges = itemSpecificSurcharges(items);
83	  return roundUpInMHPCOsFavor(
84	    policyBase + itemSurcharges + firstContractSurcharge - loyaltyDiscount + PROCESSING_FEE,
85	  );
86	};
87	
88	export const runScenario = ({ customer, steps }: Scenario): { results: unknown[] } => {
89	  const results = steps.map((step) => ({ premium: quotePremium(step, customer) }));
90	  return { results };
91	};
